import React, { useState, useEffect } from 'react';
import './App.css';

const MENU = [
  { id: 1, name: 'Капучино', price: 250, icon: '☕' },
  { id: 2, name: 'Латте', price: 280, icon: '🥛' },
  { id: 3, name: 'Круассан', price: 180, icon: '🥐' },
  { id: 4, name: 'Сэндвич', price: 350, icon: '🥪' },
];

function App() {
  const [cart, setCart] = useState(null);
  const [orderId, setOrderId] = useState(null);
  const [status, setStatus] = useState(null);

  // Функция отправки заказа
  const placeOrder = async (item) => {
    try {
      const response = await fetch('http://localhost:8000/index.php', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          description: item.name,
          total_amount: item.price
        })
      });
      const data = await response.json();

      if (data.status === "success") {
        setCart(item);
        // В реальном API бэкенд должен возвращать ID созданного заказа
        // Для теста просто запустим отслеживание
        setStatus("Ожидает");
      }
    } catch (err) {
      alert("Ошибка при оформлении заказа");
    }
  };

  // Имитация отслеживания статуса (в реальности — повторный запрос к API)
  useEffect(() => {
    if (status === "Ожидает") {
      const timer = setTimeout(() => setStatus("Готовится"), 5000);
      return () => clearTimeout(timer);
    }
    if (status === "Готовится") {
      const timer = setTimeout(() => setStatus("Готов!"), 7000);
      return () => clearTimeout(timer);
    }
  }, [status]);

  return (
    <div className="app-container">
      <header>
        <h1 style={{ color: '#2d3436' }}>Etika Coffee</h1>
        <p style={{ color: '#636e72' }}>Выберите напиток или закуску:</p>
      </header>

      <div className="menu-grid">
        {MENU.map(item => (
          <div key={item.id} className="menu-item" onClick={() => placeOrder(item)}>
            <span>{item.icon}</span>
            <h3>{item.name}</h3>
            <p>{item.price} ₽</p>
          </div>
        ))}
      </div>

      {status && (
        <div className="order-status-card">
          <h3>Ваш заказ: {cart?.name}</h3>
          <p>Статус: <span className="status-badge">{status}</span></p>
          {status === "Готов!" && <p>🎉 Заберите на стойке!</p>}
        </div>
      )}
    </div>
  );
}

export default App;
